class MapPickerViewModel extends ChangeNotifier {
  LatLng? selectedLatLng;
  double radiusMeters = 200;
  String label = '';
  bool isSaving = false;

  void selectLocation(LatLng latLng) { selectedLatLng = latLng; notifyListeners(); }
  void updateRadius(double meters) { radiusMeters = meters; notifyListeners(); }
  void updateLabel(String value) { label = value; notifyListeners(); }

  Future<void> saveLocation({
    required String listId,
    required AssignLocationUseCase assignLocation,
    required RegisterGeofenceUseCase registerGeofence,
    required TodoListRepository listRepo,
  }) async {
    if (selectedLatLng == null) return;
    isSaving = true; notifyListeners();
    // 1. AssignLocationUseCase — upserts geofence, updates list.geofenceId
    await assignLocation(listId: listId, lat: selectedLatLng!.latitude,
        lng: selectedLatLng!.longitude, radiusMeters: radiusMeters, label: label);
    // 2. RegisterGeofenceUseCase — calls StubGeofenceService.registerRegion in Phase 2
    final list = await listRepo.getListById(listId);
    if (list?.geofenceId != null) await registerGeofence(list!.geofenceId!);
    isSaving = false; notifyListeners();
  }

  Future<void> removeLocation({
    required String listId,
    required TodoListRepository listRepo,
    required GeofenceRepository geofenceRepo,
    required UnregisterGeofenceUseCase unregisterGeofence,
  }) async {
    final list = await listRepo.getListById(listId);
    if (list?.geofenceId == null) return;
    // 1. Unregister from OS (stub in Phase 2) + set isActive=false in DB
    await unregisterGeofence(list!.geofenceId!);
    // 2. Clear geofenceId on the list
    await listRepo.saveList(list.copyWith(geofenceId: null));
  }
}
