### `FlutterNotificationService` (lib/src/flutter_notification_service.dart)
Implements `NotificationService` from domain:

```dart
class FlutterNotificationService implements NotificationService {
  final FlutterLocalNotificationsPlugin _plugin = FlutterLocalNotificationsPlugin();

  @override
  Future<void> initialize() async {
    const iosSettings = DarwinInitializationSettings(
      requestAlertPermission: false,  // we request separately via permission_handler
      requestBadgePermission: false,
      requestSoundPermission: false,
    );
    const androidSettings = AndroidInitializationSettings('@mipmap/ic_launcher');
    await _plugin.initialize(
      const InitializationSettings(iOS: iosSettings, android: androidSettings),
      onDidReceiveNotificationResponse: _onNotificationTapped,
    );
  }

  @override
  Future<void> postListNotification({
    required String listId,
    required String listTitle,
    required int incompleteCount,
  }) async {
    final body = incompleteCount == 1
        ? '1 item remaining'
        : '$incompleteCount items remaining';
    await _plugin.show(
      listId.hashCode,   // notification ID (int)
      listTitle,
      body,
      _notificationDetails(),
      payload: listId,   // listId passed here for deep-link
    );
  }

  void _onNotificationTapped(NotificationResponse response) {
    final listId = response.payload;
    if (listId != null) {
      // Navigate to /list/:listId
      // Use a global navigator key or router callback registered via setNotificationTapCallback
      _tapCallback?.call(listId);
    }
  }

  void Function(String listId)? _tapCallback;
  void setNotificationTapCallback(void Function(String listId) callback) {
    _tapCallback = callback;
  }

  @override
  Future<bool> requestPermission() async {
    // iOS: request via flutter_local_notifications DarwinNotificationDetails
    final result = await _plugin
        .resolvePlatformSpecificImplementation<IOSFlutterLocalNotificationsPlugin>()
        ?.requestPermissions(alert: true, badge: true, sound: true);
    return result ?? false;
  }
}
```

